"use strict";parserFactory.register("peachblossomcodex.com",()=>new PeachblossomcodexParser);class PeachblossomcodexParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=e.querySelector("div.pbc_novel_chapters_wrapper");return util.hyperlinksToChapterList(r)}findContent(e){return e.querySelector("div.et_pb_row_inner_1_tb_body")}extractTitleImpl(e){return e.querySelector("h4.et_pb_module_header")}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div#main-content")}preprocessRawDom(e){let r=this.findContent(e),t=e.querySelector("div.et_pb_row_inner_2_tb_body");null!==t&&r.append(t);let o=[...r.querySelectorAll(".wpcmtt")];this.moveFootnotes(e,r,o)}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.et_pb_module.et_pb_post_content")]}}